mapper.select:
SELECT ccl.id, ccl.course_code, ccl.college_id, col.college_name, c.course_name FROM edu_course_college_limit ccl LEFT JOIN edu_college col ON ccl.college_id = col.id LEFT JOIN edu_course c ON ccl.course_code = c.course_code
AND ccl.course_code = #{courseCode}
AND ccl.college_id = #{collegeId}
ORDER BY ccl.course_code, ccl.college_id
